const PRESET_SPRITES={link:{name:'Link',icon:'⚔️',title:'The Chosen Hero',img:"data:image/png;base64,"},zelda:{name:'Zelda',icon:'👑',title:'Princess of Hyrule',img:"data:image/png;base64,"},lana:{name:'Lana',icon:'📖',title:'Guardian Sorceress',img:"data:image/png;base64,"},impa:{name:'Impa',icon:'🛡️',title:'The Shiekah Warrior',img:"data:image/png;base64,"},linkle:{name:'Linkle',icon:'🏹',title:'The Lost Heroine',img:"data:image/png;base64,"},fi:{name:'Fi',icon:'💠',title:'Spirit of the Sword',img:"data:image/png;base64,"},wolf_link:{name:'Wolf Link',icon:'🐺',title:'The Twilight Beast',img:"data:image/png;base64,"},darunia:{name:'Darunia',icon:'🪨',title:'Goron Sage',img:"data:image/png;base64,"},ruto:{name:'Ruto',icon:'🌊',title:'Zora Princess',img:"data:image/png;base64,"},sheik:{name:'Sheik',icon:'🌙',title:'The Mysterious Ninja',img:"data:image/png;base64,"},ganondorf:{name:'Ganondorf',icon:'💀',title:'King of Evil',img:"data:image/png;base64,"},ghirahim:{name:'Ghirahim',icon:'🗡️',title:'Demon Lord',img:"data:image/png;base64,"},zant:{name:'Zant',icon:'🌀',title:'Usurper King',img:"data:image/png;base64,"},};function renderSprite(containerEl,spriteKey,size){if(!containerEl)return;const sprite=PRESET_SPRITES[spriteKey]||PRESET_SPRITES.link;containerEl.innerHTML='<img src="'+sprite.img+'" style="width:'+(size||80)+'px;height:'+(size||80)+'px;object-fit:contain;image-rendering:pixelated;" alt="'+sprite.name+'">';}function renderSpriteToCanvas(canvas,spriteKey){if(!canvas)return;const sprite=PRESET_SPRITES[spriteKey]||PRESET_SPRITES.link;const img=new Image();img.onload=()=>{const ctx=canvas.getContext('2d');ctx.clearRect(0,0,canvas.width,canvas.height);ctx.drawImage(img,0,0,canvas.width,canvas.height);};img.src=sprite.img;}